            // But this is not accurate. Instead, we need to track the number of 'L's before each 'C'
            // So, we'll need to precompute this
            // For simplicity, we'll compute it during the first pass
        }

        // The best we can get from inserting at this position is the maximum of the three options
        long currentBest = Math.max(lInsert, Math.max(cInsert, tInsert));
        if (currentBest > bestInsert) {
            bestInsert = currentBest;
        }

        if (i < n) {
            char ch = s.charAt(i);
            if (ch == 'L') {
                lSoFar++;
            }
        }
    }

    // Now, compute tInsert correctly
    // We need to find for each position i, the number of 'C's before i that have at least one 'L' before them
    // and the number of 'T's after i
    // So, we'll precompute the number of 'C's up to each position that have 'L's before them
    long[] validCs = new long[n + 1];
    long hasL = 0;
    long validC = 0;
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        if (ch == 'L') {
            hasL = 1;
        } else if (ch == 'C') {
            validC += hasL;
        }
        validCs[i + 1] = validC;
    }

    // Now, iterate through the string again to compute tInsert
    for (int i = 0; i <= n; i++) {
        long tInsert = validCs[i] * tsAfter[i];
        if (tInsert > bestInsert) {
            bestInsert = tInsert;
        }
    }

    // The maximum possible LCT is the original count plus the best insert
    return maxLCT + bestInsert;
