    long[] prefixC = new long[n + 1];

    for (int i = 0; i < n; i++) {
        prefixC[i + 1] = prefixC[i] + (s.charAt(i) == 'C' ? 1 : 0);
    }

    long maxGainT = 0;
    for (int i = 0; i <= n; i++) {
