public static long solve(String s) {
    long lCount = 0;
    long cCount = 0;
    long tCount = 0;
    long maxL = 0;
    long maxC = 0;

    // First pass: count L's, C's, and T's, and track the maximum possible L and C counts
    for (char ch : s.toCharArray()) {
        if (ch == 'L') {
            lCount++;
        } else if (ch == 'C') {
            cCount += lCount;
        } else if (ch == 'T') {
            tCount += cCount;
        }
    }

    // The original count without any insertion
    long original = tCount;

    // Now, consider inserting each possible character at each possible position
    // To maximize the count, we can either:
    // 1. Insert 'L' to increase the L count (which will multiply the C and T counts)
    // 2. Insert 'C' to increase the C count (which will multiply the T count)
    // 3. Insert 'T' which won't help (since it's the last character)

    // Case 1: Insert 'L' at the best position (anywhere)
    // The new L count is lCount + 1
    // The new C count is cCount + (lCount + 1) * newCs (but newCs is 0 since we're inserting 'L')
    // The new T count is tCount + (cCount) * newTs (but newTs is 0)
    // So the total becomes (lCount + 1) * cCount_after_L_insertion * tCount_after_L_insertion
    // But since inserting 'L' increases the L count, the new total is (lCount + 1) * cCount * tCount / (lCount * cCount * tCount) ??
    // Actually, inserting 'L' will increase the potential for future 'C's and 'T's
    // So the new total is (lCount + 1) * cCount * tCount / (lCount * cCount * tCount) is not correct
    // Instead, the new total is the original tCount plus the new possibilities introduced by the new 'L'
    // The new 'L' can be before any existing 'C's and 'T's
    // So the new total is original + (number of 'C's after insertion point) * (number of 'T's after insertion point)
    // But to maximize, we can insert 'L' at the beginning, so all 'C's and 'T's come after it
    long case1 = (lCount + 1) * cCount;

    // Case 2: Insert 'C' at the best position (anywhere between L's and T's)
    // The new C count is cCount + lCount (since the new 'C' can pair with all existing 'L's)
    // The new T count is tCount + (cCount + lCount) * newTs (but newTs is 0)
    // So the total becomes lCount * (cCount + 1) * tCount / (lCount * cCount * tCount) ??
    // Similar to case1, inserting 'C' increases the potential for 'T's
    // The new total is original + (number of 'T's after insertion point) * (number of 'L's before insertion point)
    // To maximize, insert 'C' right after all 'L's, so all 'T's come after it
    long case2 = lCount * (cCount + lCount);

    // Case 3: Insert 'T' which doesn't help
    long case3 = original;

    // The maximum possible is the max among original, case1, and case2
    long max = Math.max(original, Math.max(case1, case2));

    return max;
