    // Calculate the original count without any insertion
    long originalCount = 0;
    int lCount = 0;
    for (int i = 0; i < n; i++) {
        char c = s.charAt(i);
        if (c == 'L') {
            lCount++;
        } else if (c == 'C') {
            originalCount += lCount * tCount[i + 1];
        }
    }
    maxCount = originalCount;

    // Try inserting 'L' at every possible position
    long insertL = 0;
    lCount = 0;
    for (int i = 0; i <= n; i++) {
        // The count if we insert 'L' at position i
        long current = 0;
        if (i < n) {
            current = lCount * cCount[i] * tCount[i];
        } else {
            current = lCount * cCount[i] * tCount[i];
        }
        insertL = Math.max(insertL, current);
        if (i < n && s.charAt(i) == 'L') {
            lCount++;
        }
    }
    maxCount = Math.max(maxCount, originalCount + insertL);

    // Try inserting 'C' at every possible position
    long insertC = 0;
    lCount = 0;
    int totalC = cCount[0];
    for (int i = 0; i <= n; i++) {
        // The count if we insert 'C' at position i
        long current = 0;
        if (i < n) {
            current = lCount * tCount[i];
        } else {
            current = lCount * tCount[i];
        }
        insertC = Math.max(insertC, current);
        if (i < n && s.charAt(i) == 'L') {
            lCount++;
        }
    }
    maxCount = Math.max(maxCount, originalCount + insertC);

    // Try inserting 'T' at every possible position
    long insertT = 0;
    lCount = 0;
    int totalT = tCount[0];
    for (int i = 0; i <= n; i++) {
        // The count if we insert 'T' at position i
        long current = 0;
        if (i < n) {
